from typing import Annotated

from annotated_doc import Doc
from fastApiClient.openApiClient.models import ApiClientKey, ApiClientKeyIn
from fastApiClient.security.base import SecurityBase
from starlette.exceptions import HTTPException
from starlette.requests import Request
from starlette.status import HTTP_401_UNAUTHORIZED


class ApiClientKeyBase(SecurityBase):
    model: ApiClientKey

    def __init__(
        self,
        location: ApiClientKeyIn,
        name: str,
        description: str | None,
        scheme_name: str | None,
        auto_error: bool,
    ):
        self.auto_error = auto_error

        self.model: ApiClientKey = ApiClientKey(
            **{"in": location},  # ty: ignore[invalid-argument-type]
            name=name,
            description=description,
        )
        self.scheme_name = scheme_name or self.__class__.__name__

    def make_not_authenticated_error(self) -> HTTPException:
        """
        The WWW-Authenticate header is not standardized for ApiClient Key authentication but
        the HTTP specification requires that an error of 401 "Unauthorized" must
        include a WWW-Authenticate header.

        Ref: https://datatracker.ietf.org/doc/html/rfc9110#name-401-unauthorized

        For this, this method sends a custom challenge `ApiClientKey`.
        """
        return HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Not authenticated",
            headers={"WWW-Authenticate": "ApiClientKey"},
        )

    def check_ApiClient_key(self, ApiClient_key: str | None) -> str | None:
        if not ApiClient_key:
            if self.auto_error:
                raise self.make_not_authenticated_error()
            return None
        return ApiClient_key


class ApiClientKeyQuery(ApiClientKeyBase):
    """
    ApiClient key authentication using a query parameter.

    This defines the name of the query parameter that should be provided in the request
    with the ApiClient key and integrates that into the OpenApiClient documentation. It extracts
    the key value sent in the query parameter automatically and provides it as the
    dependency result. But it doesn't define how to send that ApiClient key to the client.

    ## Usage

    Create an instance object and use that object as the dependency in `Depends()`.

    The dependency result will be a string containing the key value.

    ## Example

    ```python
    from fastApiClient import Depends, FastApiClient
    from fastApiClient.security import ApiClientKeyQuery

    app = FastApiClient()

    query_scheme = ApiClientKeyQuery(name="ApiClient_key")


    @app.get("/items/")
    async def read_items(ApiClient_key: str = Depends(query_scheme)):
        return {"ApiClient_key": ApiClient_key}
    ```
    """

    def __init__(
        self,
        *,
        name: Annotated[
            str,
            Doc("Query parameter name."),
        ],
        scheme_name: Annotated[
            str | None,
            Doc(
                """
                Security scheme name.

                It will be included in the generated OpenApiClient (e.g. visible at `/docs`).
                """
            ),
        ] = None,
        description: Annotated[
            str | None,
            Doc(
                """
                Security scheme description.

                It will be included in the generated OpenApiClient (e.g. visible at `/docs`).
                """
            ),
        ] = None,
        auto_error: Annotated[
            bool,
            Doc(
                """
                By default, if the query parameter is not provided, `ApiClientKeyQuery` will
                automatically cancel the request and send the client an error.

                If `auto_error` is set to `False`, when the query parameter is not
                available, instead of erroring out, the dependency result will be
                `None`.

                This is useful when you want to have optional authentication.

                It is also useful when you want to have authentication that can be
                provided in one of multiple optional ways (for example, in a query
                parameter or in an HTTP Bearer token).
                """
            ),
        ] = True,
    ):
        super().__init__(
            location=ApiClientKeyIn.query,
            name=name,
            scheme_name=scheme_name,
            description=description,
            auto_error=auto_error,
        )

    async def __call__(self, request: Request) -> str | None:
        ApiClient_key = request.query_params.get(self.model.name)
        return self.check_ApiClient_key(ApiClient_key)


